%% QEA2: Rover Mission - Map Selection & Leaderboard Setup
clc; clear; close all;

filename = 'leaderboard_data.mat';
if isfile(filename), load(filename);
else, saved_seeds = []; saved_complexities = []; saved_amplitudes = []; end

fprintf('=== Welcome to the Rover Fuel Optimization Challenge ===\n'); %[output:641099e2]
mode = input('Choose Mode: [1] New Terrain | [2] Play Seed from Leaderboard: ');

if mode == 2 && ~isempty(saved_seeds) %[output:group:14ba9612]
    T = table(saved_seeds, saved_complexities, saved_amplitudes, 'VariableNames', {'Seed', 'Complexity', 'Amplitude'});
    disp(T); %[output:06e21b80]
    choice = input('Enter the Seed you want to play: ');
    idx = find(saved_seeds == choice, 1);
    seed = saved_seeds(idx); complexity = saved_complexities(idx); amplitude = saved_amplitudes(idx);
else
    seed = randi(10000); complexity = 0.5; amplitude = 10; % Defaults for new
end %[output:group:14ba9612]


fig = figure('Color', 'w', 'Name', 'Terrain Designer', 'Position', [100, 100, 1000, 700]); %[output:99e6c52e]
ax = axes('Parent', fig, 'Position', [0.13, 0.3, 0.77, 0.6]); %[output:99e6c52e]

% Slider for Complexity
sld_comp = uicontrol('Parent', fig, 'Style', 'slider', 'Units', 'normalized', ... %[output:99e6c52e]
    'Position', [0.3, 0.15, 0.4, 0.05], 'value', complexity, 'min', 0.1, 'max', 2.0); %[output:99e6c52e]
uicontrol('Parent', fig, 'Style', 'text', 'Units', 'normalized', ... %[output:99e6c52e]
    'Position', [0.3, 0.2, 0.4, 0.03], 'String', 'Complexity (Frequency)', 'BackgroundColor', 'w'); %[output:99e6c52e]

% Slider for Amplitude
sld_amp = uicontrol('Parent', fig, 'Style', 'slider', 'Units', 'normalized', ... %[output:99e6c52e]
    'Position', [0.3, 0.05, 0.4, 0.05], 'value', amplitude, 'min', 1, 'max', 30); %[output:99e6c52e]
uicontrol('Parent', fig, 'Style', 'text', 'Units', 'normalized', ... %[output:99e6c52e]
    'Position', [0.3, 0.1, 0.4, 0.03], 'String', 'Amplitude (Scale)', 'BackgroundColor', 'w'); %[output:99e6c52e]

% Save Button
uicontrol('Parent', fig, 'Style', 'pushbutton', 'Units', 'normalized', ... %[output:99e6c52e]
    'Position', [0.8, 0.05, 0.15, 0.1], 'String', 'Save & Start', ... %[output:99e6c52e]
    'Callback', @(src, event) saveAndQuit(filename, seed, sld_comp.Value, sld_amp.Value)); %[output:99e6c52e]

% Real-time Update Loop
[x, y] = meshgrid(-10:0.2:10, -10:0.2:10);
rng(seed); p1 = rand * 2*pi; p2 = rand * 2*pi;

while ishandle(fig) %[output:group:81c4bd3f]
    % Update values from sliders
    comp = sld_comp.Value;
    amp = sld_amp.Value;
    
    % Re-calculate terrain
    z = amp * (sin(comp*x + p1) .* cos(comp*y + p2));
    
    % Update plot
    cla(ax);
    surf(ax, x, y, z, 'EdgeColor', 'none'); %[output:99e6c52e]
    colormap summer; colorbar; lighting gouraud; camlight;
    title(ax, sprintf('Seed: %d | Complexity: %.2f | Amplitude: %.2f', seed, comp, amp));
    zlim([-35 35]);
    
    drawnow;
end %[output:group:81c4bd3f]

% Callback Function to Save Data
function saveAndQuit(fname, s, c, a)
    if isfile(fname), load(fname); 
    else, saved_seeds=[]; saved_complexities=[]; saved_amplitudes=[]; end
    
    saved_seeds = [saved_seeds; s];
    saved_complexities = [saved_complexities; c];
    saved_amplitudes = [saved_amplitudes; a];
    save(fname, 'saved_seeds', 'saved_complexities', 'saved_amplitudes');
    fprintf('\nTerrain Saved! Closing designer...\n');
    close(gcf);
end

